blocks.body:
{
    "level": "A2–B1",
    "intro": "W tym temacie dowiesz się <strong>słów liczbowych</strong>: <strong>much, many, a lot of, less, small</strong> - jak poprawnie ich używać z policzalnymi i niepoliczalnymi rzeczowniki.",
    "rules": [
        {
            "label": "Wiele",
            "color": "emerald",
            "text": "<strong>Wiele</strong> – wiele (policzalne):",
            "example": "wiele książek, wielu przyjaciół, wiele pomysłów"
        },
        {
            "label": "Dużo",
            "color": "blue",
            "text": "<strong>Dużo</strong> – wiele (niepoliczalne):",
            "example": "dużo czasu, dużo pieniędzy, dużo wody"
        },
        {
            "label": "dużo",
            "color": "amber",
            "text": "<strong>dużo</strong> - dużo (oba typy):",
            "example": "dużo książek, dużo czasu"
        }
    ]
}

{
    "title": "1. Co to są kwantyfikatory?",
    "intro": "Kwantyfikatory to słowa wskazujące ilość:",
    "items": [
        {
            "label": "Dużo/Wiele",
            "title": "Wiele",
            "subtitle": "Dużo z niepoliczalnymi, Wiele z policzalnymi"
        },
        {
            "label": "Dużo of",
            "title": "Wiele (uniwersalne)",
            "subtitle": "Odpowiednie dla obu typów rzeczowników"
        },
        {
            "label": "Mało/Mało",
            "title": "Kilka",
            "subtitle": "Kilka z liczbami policzalnymi, Mało z niepoliczalne"
        }
    ]
}

{
    "title": "2. Wiele – z rzeczownikami policzalnymi",
    "sections": [
        {
            "label": "Reguła",
            "color": "emerald",
            "description": "<strong>Wiele</strong> jest używana z <strong>rzeczownikami policzalnymi w liczbie mnogiej</strong>.",
            "examples": [
                {
                    "en": "wiele książek",
                    "ua": "wiele książek"
                },
                {
                    "en": "wielu znajomych",
                    "ua": "wielu znajomych"
                },
                {
                    "en": "wiele osób",
                    "ua": "wiele osób"
                },
                {
                    "en": "wiele pomysłów",
                    "ua": "wiele pomysłów"
                }
            ]
        },
        {
            "label": "W zdania",
            "color": "sky",
            "description": "Przykłady użycia <strong>wiele</strong> w różnych typach zdań:",
            "examples": [
                {
                    "en": "Ile masz książek?",
                    "ua": "Ile masz książek?"
                },
                {
                    "en": "Nie mam tu zbyt wielu przyjaciół.",
                    "ua": "Nie mam masz tu wielu przyjaciół."
                },
                {
                    "en": "W parku jest wielu ludzi.",
                    "ua": "W parku jest wielu ludzi."
                },
                {
                    "en": "Masz wiele pytań?",
                    "ua": "Masz wiele pytania?"
                }
            ]
        },
        {
            "label": "Ważne!",
            "color": "amber",
            "description": "<strong>Wiele</strong> jest częściej używane w <strong>pytaniach i zastrzeżeniach</strong>.",
            "examples": [
                {
                    "en": "❓ Ilu masz znajomych masz?",
                    "ua": "Pytanie"
                },
                {
                    "en": "❌ Nie mam zbyt wielu książek.",
                    "ua": "Sprzeciw"
                },
                {
                    "en": "✓ Mam dużo książek. (twierdzenie)",
                    "ua": "Dużo jest lepsze w twierdzących"
                }
            ],
            "note": "📌W zdaniach twierdzących lepiej jest użyć <strong>dużo</strong>."
        }
    ]
}

{
    "title": "3. Much – z rzeczownikami niepoliczalnymi",
    "sections": [
        {
            "label": "Reguła",
            "color": "blue",
            "description": "<strong>Much</strong> jest używana z <strong>rzeczownikami niepoliczalnymi</strong>.",
            "examples": [
                {
                    "en": "dużo czasu",
                    "ua": "dużo czas"
                },
                {
                    "en": "dużo pieniędzy",
                    "ua": "dużo pieniędzy"
                },
                {
                    "en": "dużo wody",
                    "ua": "dużo wody"
                },
                {
                    "en": "dużo informacji",
                    "ua": "dużo informacje"
                }
            ]
        },
        {
            "label": "W zdaniach",
            "color": "sky",
            "description": "Przykłady użycia <strong>dużo</strong> w różnych typach zdań:",
            "examples": [
                {
                    "en": "Ile pieniędzy potrzebujesz?",
                    "ua": "Ile pieniędzy potrzebujesz?"
                },
                {
                    "en": "Nie mam dzisiaj zbyt wiele czasu.[[[CODX_4]]]Nie mam dużo czasu dzisiaj.",
                    "ua": "У мене сьогодні небагато часу."
                },
                {
                    "en": "Nie zostało zbyt wiele wody.",
                    "ua": "Nie zostało już zbyt wiele wody."
                },
                {
                    "en": "Masz duże doświadczenie?",
                    "ua": "Czy masz dużo doświadczenie?"
                }
            ]
        },
        {
            "label": "Ważne!",
            "color": "amber",
            "description": "<strong>Wiele</strong> jest również częstsze w <strong>pytaniach i zastrzeżeniach</strong>.",
            "examples": [
                {
                    "en": "❓ Ile czasu poświęcasz mam?",
                    "ua": "Pytanie"
                },
                {
                    "en": "❌ Nie mam dużo pieniędzy.",
                    "ua": "Sprzeciw"
                },
                {
                    "en": "✓ Mam dużo pieniędzy. (twierdzenie)",
                    "ua": "Dużo jest lepsze w twierdzących"
                }
            ],
            "note": "📌W zdaniach twierdzących lepiej jest używać <strong>dużo</strong>."
        }
    ]
}

{
    "title": "4. A lot of / Many of - uniwersalny",
    "sections": [
        {
            "label": "W przypadku obu typów",
            "color": "purple",
            "description": "<strong>Alot of</strong> i <strong>lots of</strong> - uniwersalny, można pracować z <strong>oba typami rzeczowników</strong>.",
            "examples": [
                {
                    "en": "dużo książek (policzalne)",
                    "ua": "wiele książek (policzalne)"
                },
                {
                    "en": "dużo czasu (niepoliczalne)",
                    "ua": "dużo czasu (niepoliczalne)"
                },
                {
                    "en": "dużo przyjaciół",
                    "ua": "dużo znajomych przyjaciele"
                },
                {
                    "en": "dużo pieniędzy",
                    "ua": "dużo pieniędzy"
                }
            ]
        },
        {
            "label": "Ty twierdzisz",
            "color": "emerald",
            "description": "<strong>Dużo</strong> jest najlepsze dla <strong>zdań potwierdzających</strong>.",
            "examples": [
                {
                    "en": "Mam wielu przyjaciół.",
                    "ua": "Mam wielu przyjaciół."
                },
                {
                    "en": "Ona ma dużo czasu.",
                    "ua": "Ma dużo czasu."
                },
                {
                    "en": "Czytamy dużo książek.",
                    "ua": " Piją dużo wody. tutaj."
                },
                {
                    "en": "They drink a lot of water.",
                    "ua": "Вони пʼють багато води."
                }
            ]
        },
        {
            "label": "Lots of — неформальніше",
            "color": "sky",
            "description": "<strong>Lots of</strong> — більш неформальний варіант.",
            "examples": [
                {
                    "en": "I have lots of work to do.",
                    "ua": "У мене купа роботи."
                },
                {
                    "en": "There are lots of people here.",
                    "ua": "Jest tu dużo ludzi."
                }
            ],
            "note": "📌 <strong>Dużo</strong> jest bardziej neutralne, <strong>dużo</strong> jest bardziej konwersacyjne."
        }
    ]
}

{
    "title": "5. Niewiele - kilka (policzalne)",
    "sections": [
        {
            "label": "Niewiele - kilka (ujemne)",
            "color": "rose",
            "description": "<strong>Niewiele</strong> oznacza <strong>kilka, za mało</strong> (ton negatywny).",
            "examples": [
                {
                    "en": "Mam tu kilku przyjaciół.",
                    "ua": "Mam tu kilku przyjaciół. (za mało)"
                },
                {
                    "en": "Niewiele osób o tym wie.",
                    "ua": "Kilka osób o tym wie."
                },
                {
                    "en": "Mało książek jest na półce.",
                    "ua": "Kilka książek na półce."
                }
            ]
        },
        {
            "label": "Kilka (pozytywny)",
            "color": "emerald",
            "description": "<strong>Kilka</strong> oznacza <strong>kilka, trochę</strong> (ton pozytywny).",
            "examples": [
                {
                    "en": "Mam tu kilku przyjaciół.",
                    "ua": "Mam tu kilku przyjaciół. (wystarczy)"
                },
                {
                    "en": "Kilka osób o tym wie.",
                    "ua": "Kilka osób o tym wie."
                },
                {
                    "en": "Potrzebuję kilku minut.",
                    "ua": "Potrzebuję kilku minut."
                }
            ]
        },
        {
            "label": "Różnica Kilka a Kilka",
            "color": "amber",
            "description": "Artykuł <strong>a</strong> zmienia wartość!",
            "examples": [
                {
                    "en": "Przyszło niewiele osób. ❌ (mało, źle)",
                    "ua": "Przyszło kilka osób."
                },
                {
                    "en": "Przyszło kilka osób. ✓ (kilka, dobrze)",
                    "ua": "Przyszło kilka osób."
                }
            ],
            "note": "📌 <strong>Mało</strong> = za mało, <strong>kilka</strong> = wystarczy."
        }
    ]
}

{
    "title": "6. Mało - mało (niepoliczalne)",
    "sections": [
        {
            "label": "Mało - mało (negatywnie)",
            "color": "rose",
            "description": "<strong>Mało</strong> oznacza <strong>mało, za mało</strong> (ton negatywny).",
            "examples": [
                {
                    "en": "Mam mało czasu.",
                    "ua": "Mam mało czasu. (za mało)"
                },
                {
                    "en": "Zostało mało wody.",
                    "ua": "Mało informacji."
                },
                {
                    "en": "We have little information.",
                    "ua": "Mało informacji."
                }
            ]
        },
        {
            "label": "Trochę (pozytywnie)",
            "color": "emerald",
            "description": "<strong>Trochę</strong> znaczy <strong>mało, mało</strong> (ton pozytywny).",
            "examples": [
                {
                    "en": "Mam mało czasu.",
                    "ua": "Mam mało czasu. (wystarczy)"
                },
                {
                    "en": "Zostało trochę wody.",
                    "ua": "Potrzebuję małej pomocy."
                },
                {
                    "en": "I need a little help.",
                    "ua": "Potrzebuję małej pomocy."
                }
            ]
        },
        {
            "label": "Różnica niewielka vs. Niewiele",
            "color": "amber",
            "description": "Artykuł <strong>a</strong> zmienia wartość!",
            "examples": [
                {
                    "en": "Nie ma dużej nadziei. ❌ (mało, źle)",
                    "ua": "Jest mała nadzieja."
                },
                {
                    "en": "Jest mała nadzieja. ✓ (trochę, dobrze)",
                    "ua": "Jest mała nadzieja."
                }
            ],
            "note": "📌 <strong>Mało</strong> = za mało, <strong>trochę</strong> = wystarczy."
        }
    ]
}

{
    "title": "7. Some / Any — pewna ilość",
    "sections": [
        {
            "label": "Niektóre - twierdząco",
            "color": "sky",
            "description": "<strong>Niektóre</strong> - dla obu typów <strong>zdania twierdzące</strong>.",
            "examples": [
                {
                    "en": "Mam kilka książek.",
                    "ua": "Mam kilka książek."
                },
                {
                    "en": "Ona ma trochę pieniądze.",
                    "ua": "Ona ma trochę pieniędzy."
                },
                {
                    "en": "Potrzebujemy trochę czasu.",
                    "ua": "Potrzebujemy trochę czasu."
                }
            ]
        },
        {
            "label": "Wszelkie – w pytaniach i zastrzeżeniach",
            "color": "purple",
            "description": "<strong>Dowolne</strong> – dla obu typów w <strong>pytaniach i zastrzeżeniach zastrzeżeń.",
            "examples": [
                {
                    "en": "Masz jakieś pytania?",
                    "ua": "Masz jakieś pytania?"
                },
                {
                    "en": "Nie mam żadnych pieniędzy.",
                    "ua": "Nie mam żadnych pieniędzy."
                },
                {
                    "en": "Czy są jakieś woda?",
                    "ua": " woda?"
                }
            ]
        },
        {
            "label": "Wszechstronność",
            "color": "emerald",
            "description": "<strong>Niektóre/Jakiekolwiek</strong> działają z obydwoma rodzajami rzeczowników.",
            "examples": [
                {
                    "en": "niektóre książki / trochę wody",
                    "ua": "niektóre książki/niektóre woda"
                },
                {
                    "en": "jakikolwiek znajomi / w dowolnym momencie",
                    "ua": "kilka znajomych / w dowolnym momencie"
                }
            ]
        }
    ]
}

{
    "title": "8. Tabela porównawcza",
    "intro": "Podstawowe kwantyfikatory i ich zastosowanie:",
    "rows": [
        {
            "en": "Wiele",
            "ua": "Wiele (policzalne)",
            "note": "wiele książek, wielu przyjaciół (pytanie/sprzeciw)"
        },
        {
            "en": "dużo",
            "ua": "dużo (niepoliczalne)",
            "note": "dużo czasu, dużo pieniędzy (pytanie/sprzeciw)"
        },
        {
            "en": "dużo/dużo",
            "ua": "dużo (oba typy)",
            "note": "dużo książek/czas (szczególnie asercja)"
        },
        {
            "en": "kilka",
            "ua": "niewiele (policzalne, ujemne)",
            "note": "kilka osób (za mało)"
        },
        {
            "en": "Kilka",
            "ua": "Kilka (policzalne, dodatnie)",
            "note": "kilka znajomych (wystarczające)"
        },
        {
            "en": "Mało",
            "ua": "Mało (niepoliczalne, negatywny)",
            "note": "mało czasu (za mało)"
        },
        {
            "en": "trochę",
            "ua": "trochę (niepoliczalne, pozytywne)",
            "note": "trochę wody (wystarczającą)"
        }
    ],
    "warning": "📌 Artykuł <strong>a</strong> przed kilkoma/małymi zmianami znaczenie od negatywnego do pozytywnego!"
}

{
    "title": "9. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Dużo z rzeczownikami policzalnymi.",
            "wrong": "Mam wiele książek.",
            "right": "​​​​ <span class="font-mono">Mam wiele książek. / Mam dużo książek.</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Wiele z rzeczownikami niepoliczalnymi.",
            "wrong": "Nie mam zbyt wiele czasu.[[[CODX_19]]]​​​​​ czas.</span>",
            "right": "✅ <span class="font-mono">I don't have much time.</span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Zapominanie artykułu kilka dni wcześniej/mało.",
            "wrong": "Mam mało czasu. (nieprawidłowa wartość)",
            "right": " ✅ <span class="font-mono">Mam trochę czasu. (wartość dodatnia)</span>"
        },
        {
            "label": "Błąd 4",
            "color": "purple",
            "title": "Wielu/dużo twierdząco.",
            "wrong": "Mam wielu przyjaciół. (lepiej inaczej)",
            "right": "​​​​ <span class="font-mono">Mam wielu przyjaciół. (bardziej naturalny)</span>"
        }
    ]
}

{
    "title": "11. Ćwicz",
    "select_title": "Ćwiczenie 1. Wybierz właściwy kwantyfikator",
    "select_intro": "Wybierz właściwe słowo ilościowe dla każdego zdania.",
    "selects": [
        {
            "label": "Nie mam ___ czasu. (dużo / wiele)",
            "prompt": "Co to jest kwantyfikator?"
        },
        {
            "label": "Jakie masz ___ książki? (dużo / wiele)",
            "prompt": "Co to jest kwantyfikator?"
        },
        {
            "label": "Ona ma ___ przyjaciół. (dużo / dużo)",
            "prompt": "Co to jest kwantyfikator?"
        },
        {
            "label": "Zostało ___ wody. (kilka/mało) tak.",
            "prompt": "Який квантифікатор?"
        }
    ],
    "options": [
        "Перший варіант",
        "Другий варіант"
    ],
    "input_title": "Вправа 2. Заповни пропуски",
    "input_intro": "Напиши many, much, або a lot of.",
    "inputs": [
        {
            "before": "I have ___ work to do.",
            "after": " →"
        },
        {
            "before": "Ile ___ pieniędzy potrzebujesz?",
            "after": " →[[CODX_SEG_25]]]Jest ___ osób tutaj."
        },
        {
            "before": "There are ___ people here.",
            "after": " →"
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Korekcja błędów",
    "rephrase_intro": "Znajdź i popraw błąd za pomocą kwantyfikatora.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "Mam wiele książek.",
            "example_target": "Mam wiele książek. / Mam dużo książek."
        },
        {
            "original": "1. Ona nie ma zbyt wiele czasu.",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "2. W pomieszczeniu jest wiele osób.",
            "placeholder": "Popraw błąd"
        }
    ]
}

{
    "title": "Inne strony z kategorii Rzeczowniki, przedimki i ilość",
    "items": [
        {
            "label": "Kwantyfikatory — Dużo, Wiele, Dużo, Mało, Mało (bieżące)",
            "current": true
        },
        {
            "label": "Artykuły A / An / The — Artykuły",
            "current": false
        },
        {
            "label": "Artykuł zerowy — Artykuł zerowy",
            "current": false
        },
        {
            "label": "Rzeczowniki w liczbie mnogiej",
            "current": false
        }
    ]
}
